<template><div class="workspace-page"><section class="page-intro"><div><p>机构数据生产</p><h2>体检报告</h2><span>草稿可编辑；确认锁定后内容不可再修改。</span></div><div><el-button @click="ocrVisible=true">OCR 录入</el-button><el-button type="primary" @click="createVisible=true">手工新建</el-button></div></section><el-alert title="报告机构由当前账号的服务端绑定关系确定；机构无法搜索用户。" type="info" show-icon :closable="false"/><el-card shadow="never"><el-select v-model="status" @change="load"><el-option label="全部状态" value=""/><el-option v-for="s in statuses" :key="s.value" :label="s.label" :value="s.value"/></el-select><el-table :data="items" v-loading="loading"><el-table-column prop="display_id" label="编号"/><el-table-column prop="subject_name_snapshot" label="受检者姓名"/><el-table-column prop="subject_health_id" label="健康身份码"/><el-table-column prop="exam_date" label="体检日期"/><el-table-column label="状态"><template #default="s"><el-tag>{{label(s.row.status)}}</el-tag></template></el-table-column><el-table-column prop="indicator_count" label="指标数"/><el-table-column label="操作" width="330"><template #default="s"><el-button link @click="openDetail(s.row)">查看</el-button><el-button v-if="s.row.status==='draft'" link type="success" @click="lock(s.row)">确认锁定</el-button><el-button v-if="s.row.status==='locked'" link type="primary" @click="submit(s.row)">提交匹配</el-button><el-button v-if="['locked','waiting_match','published'].includes(s.row.status)" link type="danger" @click="withdraw(s.row)">撤下</el-button></template></el-table-column></el-table></el-card>
<el-dialog v-model="createVisible" title="新建机构报告" width="600px"><ReportIdentityForm :form="form" :packages="packages"/><template #footer><el-button @click="createVisible=false">取消</el-button><el-button type="primary" @click="create">创建草稿</el-button></template></el-dialog>
<el-dialog v-model="ocrVisible" title="OCR 录入临时报告" width="620px"><el-alert title="OCR 只生成待复核草稿；确认锁定时原文件会删除。" type="warning" show-icon :closable="false"/><input style="margin:16px 0" type="file" accept=".pdf,.png,.jpg,.jpeg,.webp" @change="ocrFile=$event.target.files?.[0]||null"/><ReportIdentityForm :form="form" :packages="packages"/><template #footer><el-button @click="ocrVisible=false">取消</el-button><el-button type="primary" :loading="ocrLoading" @click="runOcr">解析并创建草稿</el-button></template></el-dialog>
<el-drawer v-model="detailVisible" title="报告详情" size="min(850px,96vw)"><template v-if="current"><el-descriptions :column="2" border><el-descriptions-item label="姓名">{{current.subject_name_snapshot}}</el-descriptions-item><el-descriptions-item label="健康身份码">{{current.subject_health_id}}</el-descriptions-item><el-descriptions-item label="日期">{{current.exam_date}}</el-descriptions-item><el-descriptions-item label="状态">{{label(current.status)}}</el-descriptions-item></el-descriptions><el-form v-if="current.status==='draft'" inline style="margin-top:18px"><el-form-item label="标准指标"><el-select v-model="indicatorForm.indicator_dict_id" filterable><el-option v-for="i in indicators" :key="i.id" :label="`${i.name}（${i.unit||'-'}）`" :value="i.id"/></el-select></el-form-item><el-form-item label="值"><el-input v-model="indicatorForm.value"/></el-form-item><el-button type="primary" @click="addIndicator">添加</el-button></el-form><el-table :data="current.indicators||[]"><el-table-column label="指标"><template #default="s">{{s.row.indicator?.name}}</template></el-table-column><el-table-column prop="value" label="值"/><el-table-column label="单位"><template #default="s">{{s.row.indicator?.unit}}</template></el-table-column><el-table-column v-if="current.status==='draft'" width="80"><template #default="s"><el-button link type="danger" @click="removeIndicator(s.row)">删除</el-button></template></el-table-column></el-table></template></el-drawer></div></template>
<script setup>import{defineComponent,h,onMounted,reactive,ref}from"vue";import{ElButton,ElDatePicker,ElForm,ElFormItem,ElInput,ElOption,ElSelect,ElMessage,ElMessageBox}from"element-plus";import{fetchIndicatorDicts}from"../../api/indicators";import{addOrgReportIndicator,createOrgReport,deleteOrgReportIndicator,fetchOrgPackages,fetchOrgReport,fetchOrgReports,lockOrgReport,submitOrgReport,uploadOrgReportOcr,withdrawOrgReport}from"../../api/org";
const ReportIdentityForm=defineComponent({props:{form:Object,packages:Array},setup:p=>()=>h(ElForm,{labelPosition:"top"},()=>[h(ElFormItem,{label:"受检者真实姓名"},()=>h(ElInput,{modelValue:p.form.subject_name,"onUpdate:modelValue":v=>p.form.subject_name=v})),h(ElFormItem,{label:"健康身份码"},()=>h(ElInput,{modelValue:p.form.subject_health_id,"onUpdate:modelValue":v=>p.form.subject_health_id=v})),h(ElFormItem,{label:"体检日期"},()=>h(ElDatePicker,{modelValue:p.form.exam_date,"onUpdate:modelValue":v=>p.form.exam_date=v,valueFormat:"YYYY-MM-DD",style:"width:100%"})),h(ElFormItem,{label:"套餐（可选）"},()=>h(ElSelect,{modelValue:p.form.package_id,"onUpdate:modelValue":v=>p.form.package_id=v,clearable:true,style:"width:100%"},()=>[h(ElOption,{label:"暂不选择",value:null}),...(p.packages||[]).map(x=>h(ElOption,{label:x.name,value:x.id,key:x.id}))]))])});
const statuses=[{value:"draft",label:"草稿"},{value:"locked",label:"已锁定"},{value:"waiting_match",label:"等待匹配"},{value:"published",label:"已匹配"},{value:"withdrawn",label:"已撤下"}],label=v=>statuses.find(s=>s.value===v)?.label||v;const items=ref([]),packages=ref([]),indicators=ref([]),loading=ref(false),status=ref(""),createVisible=ref(false),ocrVisible=ref(false),ocrLoading=ref(false),ocrFile=ref(null),detailVisible=ref(false),current=ref(null),form=reactive({subject_name:"",subject_health_id:"",exam_date:new Date().toISOString().slice(0,10),package_id:null}),indicatorForm=reactive({indicator_dict_id:null,value:""});async function load(){loading.value=true;try{items.value=(await fetchOrgReports(status.value?{status:status.value}:{})).data.items||[]}finally{loading.value=false}}async function create(){try{await createOrgReport(form);createVisible.value=false;ElMessage.success("报告草稿已创建");await load()}catch(e){ElMessage.error(e?.response?.data?.message||"创建失败")}}async function runOcr(){if(!ocrFile.value){ElMessage.error("请选择报告文件");return}ocrLoading.value=true;try{const{data}=await uploadOrgReportOcr(ocrFile.value,form);ocrVisible.value=false;ElMessage.success(`OCR 草稿已创建，自动映射 ${data.item.indicator_count} 项，请复核`);await load();await openDetail(data.item)}catch(e){ElMessage.error(e?.response?.data?.message||"OCR 解析失败")}finally{ocrLoading.value=false}}async function openDetail(r){current.value=(await fetchOrgReport(r.id)).data.item;detailVisible.value=true}async function addIndicator(){try{await addOrgReportIndicator(current.value.id,indicatorForm);indicatorForm.value="";await openDetail(current.value)}catch(e){ElMessage.error(e?.response?.data?.message||"添加失败")}}async function removeIndicator(i){await deleteOrgReportIndicator(current.value.id,i.id);await openDetail(current.value)}async function lock(r){try{await ElMessageBox.confirm("锁定后报告和指标不可修改，确认继续？","确认锁定",{type:"warning"});await lockOrgReport(r.id);await load()}catch(e){if(e!=="cancel"&&e!=="close")ElMessage.error(e?.response?.data?.message||"锁定失败")}}async function submit(r){const{data}=await submitOrgReport(r.id);ElMessage.success(data.match_result==="matched"?"匹配成功":"进入 60 天等待期");await load()}async function withdraw(r){try{await ElMessageBox.confirm("撤下后该报告不再参与趋势聚合。","撤下报告",{type:"warning"});await withdrawOrgReport(r.id);await load()}catch(e){if(e!=="cancel"&&e!=="close")ElMessage.error("撤下失败")}}onMounted(async()=>{const[p,i]=await Promise.all([fetchOrgPackages(),fetchIndicatorDicts()]);packages.value=(p.data.items||[]).filter(x=>x.is_active);indicators.value=i.data.items||[];indicatorForm.indicator_dict_id=indicators.value[0]?.id;await load()});</script>
